package analytics

// ReplyLatencyStats holds response-time metrics across all replies.
type ReplyLatencyStats struct {
	Count        int                       `json:"count"`
	MedianHours  float64                   `json:"median_hours"`
	P90Hours     float64                   `json:"p90_hours"`
	MinHours     float64                   `json:"min_hours"`
	MaxHours     float64                   `json:"max_hours"`
	ByClass      map[string]float64        `json:"by_classification"` // classification -> median hours
}

// PersonaRate holds reply effectiveness for one job title.
type PersonaRate struct {
	Title     string  `json:"title"`
	Contacted int     `json:"contacted"`
	Replied   int     `json:"replied"`
	Rate      float64 `json:"rate"`
}

// HourBucket holds send/reply stats for one hour of day.
type HourBucket struct {
	Hour    int     `json:"hour"`
	Sent    int     `json:"sent"`
	Replied int     `json:"replied"`
	Rate    float64 `json:"rate"`
}

// TimePatterns holds time-of-day effectiveness.
type TimePatterns struct {
	BestSendHours  []int        `json:"best_send_hours"`
	WorstSendHours []int        `json:"worst_send_hours"`
	Buckets        []HourBucket `json:"hourly_buckets"`
}

// WinningPatterns holds message characteristics that correlate with replies.
type WinningPatterns struct {
	RepliedAvgWords    int     `json:"replied_avg_words"`
	NoReplyAvgWords    int     `json:"no_reply_avg_words"`
	RepliedAvgQuestions float64 `json:"replied_avg_questions"`
	NoReplyAvgQuestions float64 `json:"no_reply_avg_questions"`
	SweetSpot          string  `json:"sweet_spot"`
}

// AnalyticsSummary is the top-level output of nurge data analytics.
type AnalyticsSummary struct {
	GeneratedAt     string          `json:"generated_at"`
	ReplyLatency    *ReplyLatencyStats `json:"reply_latency,omitempty"`
	PersonaRates    []PersonaRate      `json:"persona_rates,omitempty"`
	TimePatterns    *TimePatterns      `json:"time_patterns,omitempty"`
	WinningPatterns *WinningPatterns   `json:"winning_patterns,omitempty"`
	TopInsight      string             `json:"top_insight"`
}
```

