func TestReplyLatency_Basic(t *testing.T) {
	d := seedTestDB(t)
	defer d.Close()

	insertMailbox(t, d, "mbx:1", "me@co.com")

	// Enrollment sent at 9am, reply at 1pm = 4 hours
	insertEnrollment(t, d, "enr:1", "a@co.com", "mbx:1", "2026-03-20T09:00:00Z", "hello")
	insertReply(t, d, "r:1", "enr:1", "mbx:1", "a@co.com", "interested", "2026-03-20T13:00:00Z")

	// Enrollment sent at 9am, reply at 9pm = 12 hours
	insertEnrollment(t, d, "enr:2", "b@co.com", "mbx:1", "2026-03-20T09:00:00Z", "hello")
	insertReply(t, d, "r:2", "enr:2", "mbx:1", "b@co.com", "replied", "2026-03-20T21:00:00Z")

	stats, err := ReplyLatency(d)
	if err != nil {
		t.Fatalf("ReplyLatency: %v", err)
	}
	if stats.Count != 2 {
		t.Errorf("count = %d, want 2", stats.Count)
	}
	// Median of [4, 12] = 8
	if stats.MedianHours != 8 {
		t.Errorf("median = %v, want 8", stats.MedianHours)
	}
	if stats.MinHours != 4 {
		t.Errorf("min = %v, want 4", stats.MinHours)
	}
	if stats.MaxHours != 12 {
		t.Errorf("max = %v, want 12", stats.MaxHours)
	}
	// ByClass: interested=4h, replied=12h
	if stats.ByClass["interested"] != 4 {
		t.Errorf("interested median = %v, want 4", stats.ByClass["interested"])
	}
}

func TestReplyLatency_Empty(t *testing.T) {
