	Use:   "analytics",
	Short: "Reply analytics: latency, persona rates, timing, message patterns",
	RunE:  runAnalytics,
}

func runAnalytics(cmd *cobra.Command, args []string) error {
	if !db.Exists() {
		return fmt.Errorf("no database found - run nurge first")
	}
	d, err := db.Open()
	if err != nil {
		return fmt.Errorf("open db: %w", err)
	}
	defer d.Close()

	sum, err := analytics.Summary(d)
	if err != nil {
		return fmt.Errorf("analytics: %w", err)
	}

	if analyticsFormat == "json" {
		return json.NewEncoder(os.Stdout).Encode(sum)
	}

	if lat := sum.ReplyLatency; lat != nil && lat.Count > 0 {
		fmt.Printf("Reply Latency (%d replies)\n", lat.Count)
		fmt.Printf("  Median: %.1fh  P90: %.1fh  Range: %.1fh - %.1fh\n",
			lat.MedianHours, lat.P90Hours, lat.MinHours, lat.MaxHours)
		if len(lat.ByClass) > 0 {
			fmt.Printf("  By type: ")
			first := true
			for class, med := range lat.ByClass {
				if !first {
					fmt.Printf(", ")
				}
				fmt.Printf("%s=%.1fh", class, med)
				first = false
			}
			fmt.Println()
		}
		fmt.Println()
	}

	if len(sum.PersonaRates) > 0 {
		fmt.Println("Persona Reply Rates")
		for _, pr := range sum.PersonaRates {
			fmt.Printf("  %-25s %d contacted, %d replied (%.0f%%)\n",
				pr.Title, pr.Contacted, pr.Replied, pr.Rate*100)
		}
		fmt.Println()
	}

	if tp := sum.TimePatterns; tp != nil && len(tp.Buckets) > 0 {
		fmt.Println("Time-of-Day Patterns")
		if len(tp.BestSendHours) > 0 {
			fmt.Printf("  Best hours: %v\n", tp.BestSendHours)
		}
		if len(tp.WorstSendHours) > 0 {
			fmt.Printf("  Worst hours: %v\n", tp.WorstSendHours)
		}
		fmt.Println()
	}

	if wp := sum.WinningPatterns; wp != nil && wp.RepliedAvgWords > 0 {
		fmt.Println("Winning Patterns")
		fmt.Printf("  Replied avg: %d words, %.1f questions\n", wp.RepliedAvgWords, wp.RepliedAvgQuestions)
		fmt.Printf("  No-reply avg: %d words, %.1f questions\n", wp.NoReplyAvgWords, wp.NoReplyAvgQuestions)
		fmt.Printf("  Sweet spot: %s\n", wp.SweetSpot)
		fmt.Println()
	}

	if sum.TopInsight != "" {
		fmt.Printf(">> %s\n", sum.TopInsight)
	}

	return nil
}

func init() {
	analyticsCmd.Flags().StringVar(&analyticsFormat, "format", "", "Output format (json)")
}

