253→func buildSyncBannerLine(report *sessionSyncReport) string {
254→	if report == nil || !report.Attempted {
255→		return ""
256→	}
257→	if report.Error != "" {
258→		return "Remote sync unavailable — using last local state"
259→	}
260→	if report.RowsUpserted == 0 {
261→		return ""
262→	}
263→
264→	parts := []string{}
265→	if report.Delta != nil {
266→		if report.Delta.TasksSent > 0 {
267→			parts = append(parts, fmt.Sprintf("%d follow-up%s sent", report.Delta.TasksSent, pluralSuffix(report.Delta.TasksSent)))
268→		}
269→		if report.Delta.RepliesNeedingAttention > 0 {
270→			parts = append(parts, fmt.Sprintf("%d repl%s need attention", report.Delta.RepliesNeedingAttention, pluralSuffix(report.Delta.RepliesNeedingAttention, "y", "ies")))
271→		}
272→		if report.Delta.TasksFailed > 0 {
273→			parts = append(parts, fmt.Sprintf("%d send failure%s", report.Delta.TasksFailed, pluralSuffix(report.Delta.TasksFailed)))
274→		}
275→		if len(report.Delta.AuthExpiredMailboxes) > 0 {
276→			parts = append(parts, fmt.Sprintf("%d mailbox reconnect%s needed", len(report.Delta.AuthExpiredMailboxes), pluralSuffix(len(report.Delta.AuthExpiredMailboxes))))
277→		}
278→	}
279→	if len(parts) == 0 {
280→		return fmt.Sprintf("Synced %d remote update%s", report.RowsUpserted, pluralSuffix(report.RowsUpserted))
281→	}
282→	return "While you were away: " + strings.Join(parts, " | ")
283→}
