285→func buildSyncPromptContext(report *sessionSyncReport) string {
286→	if report == nil || !report.Attempted {
287→		return ""
288→	}
289→
290→	var b strings.Builder
291→	if report.Error != "" {
292→		fmt.Fprintf(&b, "Remote sync status: unavailable (%s). Work from local state and avoid assuming cloud execution has fully caught up.\n", report.Error)
293→		return b.String()
294→	}
295→
296→	if report.RowsUpserted == 0 {
297→		b.WriteString("Remote sync status: no new execution-state changes since the last session.\n")
298→		return b.String()
299→	}
300→
301→	fmt.Fprintf(&b, "Remote sync status: pulled %d row%s across %d table%s.\n",
302→		report.RowsUpserted,
303→		pluralSuffix(report.RowsUpserted),
304→		report.TablesUpdated,
305→		pluralSuffix(report.TablesUpdated),
306→	)
307→
308→	if report.Delta == nil {
309→		return b.String()
310→	}
311→
312→	if report.Delta.TasksSent > 0 {
313→		fmt.Fprintf(&b, "Remote sends completed: %d.\n", report.Delta.TasksSent)
314→	}
315→	if report.Delta.TasksFailed > 0 {
316→		fmt.Fprintf(&b, "Remote send failures: %d. Check `nurge tasks list` and `nurge sends list` before advancing sequences.\n", report.Delta.TasksFailed)
317→	}
318→	if report.Delta.RepliesNeedingAttention > 0 {
319→		fmt.Fprintf(&b, "Replies needing attention: %d. Check `nurge replies queue` early in the session.\n", report.Delta.RepliesNeedingAttention)
320→		for _, item := range report.Delta.RecentReplies {
321→			if strings.TrimSpace(item.Subject) != "" {
322→				fmt.Fprintf(&b, "- Reply: %s (%s) — %s\n", item.ContactEmail, item.Classification, item.Subject)
323→				continue
324→			}
325→			fmt.Fprintf(&b, "- Reply: %s (%s)\n", item.ContactEmail, item.Classification)
326→		}
327→	}
328→	if report.Delta.EnrollmentsStopped > 0 {
329→		fmt.Fprintf(&b, "Enrollments stopped remotely: %d.\n", report.Delta.EnrollmentsStopped)
330→	}
331→	if report.Delta.EnrollmentsCompleted > 0 {
332→		fmt.Fprintf(&b, "Enrollments completed remotely: %d.\n", report.Delta.EnrollmentsCompleted)
333→	}
334→	if report.Delta.SuppressionsAdded > 0 {
335→		fmt.Fprintf(&b, "Suppressions added remotely: %d.\n", report.Delta.SuppressionsAdded)
336→	}
337→	if len(report.Delta.AuthExpiredMailboxes) > 0 {
338→		fmt.Fprintf(&b, "Mailbox reconnect required: %s. Guide the user to reconnect before new sends.\n", strings.Join(report.Delta.AuthExpiredMailboxes, ", "))
339→	}
340→
341→	return b.String()
342→}
