349→	for i, item := range staleSkills {
350→		if i >= 3 {
351→			break
352→		}
353→		names = append(names, item.SkillName)
354→	}
355→	return fmt.Sprintf("Skills ready for refresh: %s", strings.Join(names, ", "))
