358→func buildStrategicMemoryPromptContext(memories []session.StrategicMemory, staleSkills []session.StaleSkill) string {
359→	if len(memories) == 0 && len(staleSkills) == 0 {
360→		return ""
361→	}
362→
363→	var b strings.Builder
364→	if len(memories) > 0 {
365→		b.WriteString("Strategic memory updates:\n")
366→		for _, memory := range memories {
367→			fmt.Fprintf(&b, "- %s", memory.Summary)
368→			if len(memory.AffectedSkills) > 0 {
369→				fmt.Fprintf(&b, " Affects: %s.", strings.Join(memory.AffectedSkills, ", "))
370→			}
371→			b.WriteString("\n")
372→		}
373→	}
374→
375→	if len(staleSkills) > 0 {
376→		b.WriteString("Skills likely stale:\n")
377→		for _, item := range staleSkills {
378→			fmt.Fprintf(&b, "- %s: %s\n", item.SkillName, strings.Join(item.Reasons, "; "))
379→		}
380→		b.WriteString("If you refresh a skill, persist the new version with `nurge skills save <skill-name> --file .claude/skills/<skill-name>/SKILL.md`. Use `nurge skills stale --format json` for the full refresh list and `nurge memory list --format json` for the underlying strategic memory.\n")
381→	}
382→
383→	return b.String()
384→}
