386→func shortSyncError(err error) string {
387→	if err == nil {
388→		return ""
389→	}
390→	message := strings.TrimSpace(err.Error())
391→	if len(message) > 120 {
392→		return message[:117] + "..."
393→	}
394→	return message
395→}
396→
397→func pluralSuffix(count int, forms ...string) string {
398→	if len(forms) == 2 {
399→		if count == 1 {
400→			return forms[0]
401→		}
402→		return forms[1]
403→	}
404→	if count == 1 {
405→		return ""
406→	}
407→	return "s"
408→}
409→
410→func capitalize(s string) string {
411→	if s == "" {
412→		return s
413→	}
414→	return strings.ToUpper(s[:1]) + s[1:]
415→}
