func buildBanner(s *sessionStatus) string {
	var b strings.Builder
	ver := fmt.Sprintf("nurge %s", cmdutil.BuildVersion)

	// Line 1: Powered by Nurge
	b.WriteString("\n\nPowered by Nurge\n")
	// Line 2: Version
	fmt.Fprintf(&b, "  %s\n", ver)

	if !s.configLoaded {
		b.WriteString("  Run: nurge to get started")
		return b.String()
	}

	// --- Pre-setup: no connectors yet ---
	hasConnectors := false
	for _, c := range s.connectors {
		if c.Connected {
			hasConnectors = true
			break
		}
	}
	if !hasConnectors {
		b.WriteString("  Run /nurge:setup to connect your email and get started.")
		return b.String()
	}

	// --- Setup in progress ---
	if !s.setupCompleted {
		name := s.settings["user.name"]
		if name != "" {
			fmt.Fprintf(&b, "  Hey %s, setup in progress.\n", name)
		} else {
			b.WriteString("  Setup in progress.\n")
		}
		b.WriteString("  Run /nurge:setup to continue where you left off.")
		return b.String()
	}

	// --- Post-setup: compact rotating dashboard ---
	name := s.settings["user.name"]
	if name != "" {
		fmt.Fprintf(&b, "  Hey %s\n", name)
	}

	if syncLine := buildSyncBannerLine(s.startSync); syncLine != "" {
		fmt.Fprintf(&b, "  %s\n", syncLine)
	}
	if refreshLine := buildSkillRefreshBannerLine(s.staleSkills); refreshLine != "" {
		fmt.Fprintf(&b, "  %s\n", refreshLine)
	}

	// Pipeline dashboard (replaces rotating slots)
	if ps := s.pipelineStatus; ps != nil {
		fmt.Fprintf(&b, "  New outreach: %d/%d sent | %d ready | %d active\n",
			ps.NewOutreach.SentToday, ps.NewOutreach.DailyLimit,
			ps.NewOutreach.Ready, ps.NewOutreach.Active)
		fmt.Fprintf(&b, "  Follow-ups:  %d sent today | %d due",
			ps.FollowUps.SentToday, ps.FollowUps.DueToday)
		if ps.FollowUps.Overdue > 0 {
			fmt.Fprintf(&b, " (%d overdue)", ps.FollowUps.Overdue)
		}
		b.WriteString("\n")
		fmt.Fprintf(&b, "  Pipeline:    sourced %d | researched %d | ready %d | contacted %d | replied %d\n",
			ps.Pipeline.Sourced, ps.Pipeline.Researched, ps.Pipeline.Ready,
			ps.Pipeline.Contacted, ps.Pipeline.Replied)

		// Sources line (only if 2+ sources)
		if len(ps.BySource) >= 2 {
			fmt.Fprintf(&b, "  Sources:     ")
			for i, sp := range ps.BySource {
				if i > 0 {
					fmt.Fprintf(&b, " | ")
				}
				if sp.Contacted > 0 {
					fmt.Fprintf(&b, "%s %d (%d%% reply)", sp.Source, sp.Sourced, int(sp.ReplyRate*100))
				} else {
					fmt.Fprintf(&b, "%s %d", sp.Source, sp.Sourced)
				}
			}
			b.WriteString("\n")
		}

		// Decaying signals line
		if len(ps.DecayingSignals) > 0 {
			oldest := ps.DecayingSignals[0]
			for _, ds := range ps.DecayingSignals {
				if ds.DaysOld > oldest.DaysOld {
					oldest = ds
				}
			}
			fmt.Fprintf(&b, "  Signals:     %d cooling (oldest: %d days)\n", len(ps.DecayingSignals), oldest.DaysOld)
		}

		if ps.Nudge != nil && ps.Nudge.Type != "healthy" {
			fmt.Fprintf(&b, "  -> %s\n", ps.Nudge.Message)
		}
	} else {
		// Fallback: basic stats when pipeline data unavailable
		if s.weeklyStats != nil && s.weeklyStats.OutboundSent > 0 {
			fmt.Fprintf(&b, "  This week: %d emails sent", s.weeklyStats.OutboundSent)
			if s.weeklyStats.UniqueContacts > 0 {
				fmt.Fprintf(&b, " -> %d contacts", s.weeklyStats.UniqueContacts)
			}
			b.WriteString("\n")
		}
		fmt.Fprintf(&b, "  %s emails synced | %d skills active\n", formatCount(s.emailTotal), s.skillCount)
	}

	// Pending reply drafts
	if s.pendingReplyDrafts > 0 {
		fmt.Fprintf(&b, "  Replies:     %d open replies need action (nurge replies queue)\n", s.pendingReplyDrafts)
	}

	return b.String()
}

func buildPromptContext(s *sessionStatus) string {
	var b strings.Builder

	if !s.configLoaded || !s.setupCompleted {
		b.WriteString("You are in a Nurge workspace. Setup is not complete. ")
		b.WriteString("Guide the user to run /nurge:setup to finish configuration. ")
		b.WriteString("Do not attempt to use nurge data commands — they will have no data yet.")
		return b.String()
	}

	// User context
	name := s.settings["user.name"]
	role := s.settings["user.role"]
	if name != "" {
		fmt.Fprintf(&b, "User: %s", name)
		if role != "" {
			fmt.Fprintf(&b, " (%s)", role)
		}
		b.WriteString("\n")
	}

	b.WriteString("You are in a Nurge outbound sales workspace.\n")
	fmt.Fprintf(&b, "Status: Setup complete. %s emails synced (%d outbound). %d contacts. %d skills active.\n",
		formatCount(s.emailTotal), s.outboundTotal, s.contactCount, s.skillCount)

	// Pipeline state for LLM context
	if ps := s.pipelineStatus; ps != nil {
		fmt.Fprintf(&b, "Pipeline state: sourced=%d researched=%d ready=%d contacted=%d replied=%d\n",
			ps.Pipeline.Sourced, ps.Pipeline.Researched, ps.Pipeline.Ready,
			ps.Pipeline.Contacted, ps.Pipeline.Replied)
		fmt.Fprintf(&b, "Today: %d/%d first touches sent, %d follow-ups sent, %d follow-ups due\n",
			ps.NewOutreach.SentToday, ps.NewOutreach.DailyLimit,
			ps.FollowUps.SentToday, ps.FollowUps.DueToday)
		if ps.Nudge != nil && ps.Nudge.Type != "healthy" {
			fmt.Fprintf(&b, "PIPELINE NUDGE [%s]: %s\n", ps.Nudge.Type, ps.Nudge.Message)
			if ps.Nudge.Action != "" {
				fmt.Fprintf(&b, "Suggested action: %s\n", ps.Nudge.Action)
			}
		}
		if len(ps.BySource) > 1 {
			b.WriteString("Source effectiveness: ")
			for i, sp := range ps.BySource {
				if i > 0 {
					b.WriteString(", ")
				}
				if sp.Contacted > 0 {
					fmt.Fprintf(&b, "%s=%d%% reply (%d contacted)", sp.Source, int(sp.ReplyRate*100), sp.Contacted)
				} else {
					fmt.Fprintf(&b, "%s=%d sourced (0 contacted)", sp.Source, sp.Sourced)
				}
			}
			b.WriteString("\n")
		}
		if len(ps.ByPersona) > 0 {
			b.WriteString("Per-persona pipeline: ")
			for i, pp := range ps.ByPersona {
				if i > 0 {
					b.WriteString(", ")
				}
				fmt.Fprintf(&b, "%s: sourced=%d ready=%d contacted=%d replied=%d",
					pp.Persona, pp.Sourced, pp.Ready, pp.Contacted, pp.Replied)
			}
			b.WriteString("\n")
		}
	}

	if syncContext := buildSyncPromptContext(s.startSync); syncContext != "" {
		b.WriteString(syncContext)
	}
	if strategicContext := buildStrategicMemoryPromptContext(s.recentStrategicMemory, s.staleSkills); strategicContext != "" {
		b.WriteString(strategicContext)
	}

	// KPI context
	goal := s.settings["kpi.goal"]
	dailyTarget := s.settings["kpi.daily_emails"]
	weeklyMeetings := s.settings["kpi.weekly_meetings"]
	if goal != "" {
		fmt.Fprintf(&b, "Outbound goal: %s.", goal)
		if dailyTarget != "" {
			fmt.Fprintf(&b, " Daily target: %s emails.", dailyTarget)
		}
		if weeklyMeetings != "" {
			fmt.Fprintf(&b, " Weekly meeting target: %s.", weeklyMeetings)
		}
		b.WriteString("\n")
	}

	// Sending context
	warmup := s.settings["sending.warmup_status"]
	domainType := s.settings["sending.domain_type"]
	if warmup == "fresh" {
		b.WriteString("IMPORTANT: Domain is fresh/not warmed up. Enforce conservative sending limits. Do not exceed daily target.\n")
	}
	if domainType == "primary" {
		b.WriteString("Note: User is sending from primary business domain. Be conservative with volume.\n")
	}

	// Geography / compliance
	geo := s.settings["prospects.geography"]
	if geo != "" {
		fmt.Fprintf(&b, "Prospect geography: %s.", geo)
		if strings.Contains(strings.ToLower(geo), "eu") || strings.Contains(strings.ToLower(geo), "europe") {
			b.WriteString(" GDPR applies — ensure legitimate interest basis for outreach.")
		}
		b.WriteString("\n")
	}

	// Rules
	b.WriteString("Rules:\n")
	b.WriteString("- Use `nurge` CLI commands for all data access. Never read .nurge/ directly.\n")
	b.WriteString("- For ICP, personas, and product context: nurge config show --format json\n")
	b.WriteString("- For email patterns and insights: nurge context generate --format json\n")
	b.WriteString("- For email stats: nurge emails stats --format json\n")
	b.WriteString("- For pipeline status: nurge pipeline status --format json\n")
	b.WriteString("- When sending emails: nurge send (always get user approval first)\n")
	b.WriteString("- When researching prospects: use WebSearch with multiple angles, check company legal pages (mentions légales, impressum), cross-reference before drafting")

	if len(s.skillNames) > 0 {
		fmt.Fprintf(&b, "\nAvailable skills: %s", strings.Join(s.skillNames, ", "))
	}

	return b.String()
}

func buildSyncBannerLine(report *sessionSyncReport) string {
	if report == nil || !report.Attempted {
		return ""
	}
	if report.Error != "" {
		return "Remote sync unavailable — using last local state"
	}
	if report.RowsUpserted == 0 {
		return ""
	}

	parts := []string{}
	if report.Delta != nil {
		if report.Delta.TasksSent > 0 {
			parts = append(parts, fmt.Sprintf("%d follow-up%s sent", report.Delta.TasksSent, pluralSuffix(report.Delta.TasksSent)))
		}
		if report.Delta.RepliesNeedingAttention > 0 {
			parts = append(parts, fmt.Sprintf("%d repl%s need attention", report.Delta.RepliesNeedingAttention, pluralSuffix(report.Delta.RepliesNeedingAttention, "y", "ies")))
		}
		if report.Delta.TasksFailed > 0 {
			parts = append(parts, fmt.Sprintf("%d send failure%s", report.Delta.TasksFailed, pluralSuffix(report.Delta.TasksFailed)))
		}
		if len(report.Delta.AuthExpiredMailboxes) > 0 {
			parts = append(parts, fmt.Sprintf("%d mailbox reconnect%s needed", len(report.Delta.AuthExpiredMailboxes), pluralSuffix(len(report.Delta.AuthExpiredMailboxes))))
		}
	}
	if len(parts) == 0 {
		return fmt.Sprintf("Synced %d remote update%s", report.RowsUpserted, pluralSuffix(report.RowsUpserted))
	}
	return "While you were away: " + strings.Join(parts, " | ")
}

func buildSyncPromptContext(report *sessionSyncReport) string {
	if report == nil || !report.Attempted {
		return ""
	}

	var b strings.Builder
	if report.Error != "" {
		fmt.Fprintf(&b, "Remote sync status: unavailable (%s). Work from local state and avoid assuming cloud execution has fully caught up.\n", report.Error)
		return b.String()
	}

	if report.RowsUpserted == 0 {
		b.WriteString("Remote sync status: no new execution-state changes since the last session.\n")
		return b.String()
	}

	fmt.Fprintf(&b, "Remote sync status: pulled %d row%s across %d table%s.\n",
		report.RowsUpserted,
		pluralSuffix(report.RowsUpserted),
		report.TablesUpdated,
		pluralSuffix(report.TablesUpdated),
	)

	if report.Delta == nil {
		return b.String()
	}

	if report.Delta.TasksSent > 0 {
		fmt.Fprintf(&b, "Remote sends completed: %d.\n", report.Delta.TasksSent)
	}
	if report.Delta.TasksFailed > 0 {
		fmt.Fprintf(&b, "Remote send failures: %d. Check `nurge tasks list` and `nurge sends list` before advancing sequences.\n", report.Delta.TasksFailed)
	}
	if report.Delta.RepliesNeedingAttention > 0 {
		fmt.Fprintf(&b, "Replies needing attention: %d. Check `nurge replies queue` early in the session.\n", report.Delta.RepliesNeedingAttention)
		for _, item := range report.Delta.RecentReplies {
			if strings.TrimSpace(item.Subject) != "" {
				fmt.Fprintf(&b, "- Reply: %s (%s) — %s\n", item.ContactEmail, item.Classification, item.Subject)
				continue
			}
			fmt.Fprintf(&b, "- Reply: %s (%s)\n", item.ContactEmail, item.Classification)
		}
	}
	if report.Delta.EnrollmentsStopped > 0 {
		fmt.Fprintf(&b, "Enrollments stopped remotely: %d.\n", report.Delta.EnrollmentsStopped)
	}
	if report.Delta.EnrollmentsCompleted > 0 {
		fmt.Fprintf(&b, "Enrollments completed remotely: %d.\n", report.Delta.EnrollmentsCompleted)
	}
	if report.Delta.SuppressionsAdded > 0 {
		fmt.Fprintf(&b, "Suppressions added remotely: %d.\n", report.Delta.SuppressionsAdded)
	}
	if len(report.Delta.AuthExpiredMailboxes) > 0 {
		fmt.Fprintf(&b, "Mailbox reconnect required: %s. Guide the user to reconnect before new sends.\n", strings.Join(report.Delta.AuthExpiredMailboxes, ", "))
	}

	return b.String()
}

func buildSkillRefreshBannerLine(staleSkills []session.StaleSkill) string {
	if len(staleSkills) == 0 {
		return ""
	}
	names := make([]string, 0, len(staleSkills))
	for i, item := range staleSkills {
		if i >= 3 {
			break
		}
		names = append(names, item.SkillName)
	}
	return fmt.Sprintf("Skills ready for refresh: %s", strings.Join(names, ", "))
}

func buildStrategicMemoryPromptContext(memories []session.StrategicMemory, staleSkills []session.StaleSkill) string {
	if len(memories) == 0 && len(staleSkills) == 0 {
		return ""
	}

	var b strings.Builder
	if len(memories) > 0 {
		b.WriteString("Strategic memory updates:\n")
		for _, memory := range memories {
			fmt.Fprintf(&b, "- %s", memory.Summary)
			if len(memory.AffectedSkills) > 0 {
				fmt.Fprintf(&b, " Affects: %s.", strings.Join(memory.AffectedSkills, ", "))
			}
			b.WriteString("\n")
		}
	}

	if len(staleSkills) > 0 {
		b.WriteString("Skills likely stale:\n")
		for _, item := range staleSkills {
			fmt.Fprintf(&b, "- %s: %s\n", item.SkillName, strings.Join(item.Reasons, "; "))
		}
		b.WriteString("If you refresh a skill, persist the new version with `nurge skills save <skill-name> --file .claude/skills/<skill-name>/SKILL.md`. Use `nurge skills stale --format json` for the full refresh list and `nurge memory list --format json` for the underlying strategic memory.\n")
	}

	return b.String()
}

func shortSyncError(err error) string {
	if err == nil {
		return ""
	}
	message := strings.TrimSpace(err.Error())
	if len(message) > 120 {
		return message[:117] + "..."
	}
	return message
}

func pluralSuffix(count int, forms ...string) string {
	if len(forms) == 2 {
		if count == 1 {
			return forms[0]
		}
		return forms[1]
	}
	if count == 1 {
		return ""
	}
	return "s"
}

func capitalize(s string) string {
	if s == "" {
		return s
	}
	return strings.ToUpper(s[:1]) + s[1:]
}

func formatCount(n int) string {
	if n >= 1000 {
		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
	}
	return fmt.Sprintf("%d", n)
}
